{
  "name": "Gemini Live Voice Assistant",
  "description": "A real-time voice assistant powered by Gemini 2.5 Flash Native Audio.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ConnectionState {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR',
}

export interface AudioVisualizerProps {
  analyser: AnalyserNode | null;
  isConnected: boolean;
}

import { Blob } from '@google/genai';

export function base64ToBytes(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function bytesToBase64(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: bytesToBase64(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { ConnectionState } from '../types';
import { createPcmBlob, base64ToBytes, decodeAudioData } from '../utils/audio-utils';

export const useGeminiLive = () => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [error, setError] = useState<string | null>(null);

  // Audio Contexts and Nodes
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Session Management
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);

  const disconnect = useCallback(async () => {
    // 1. Close session if possible (wrapper doesn't expose explicit close on promise, 
    // but we stop sending data and close contexts)
    // There is no explicit .close() on the session object in the current SDK version provided in the prompt examples, 
    // but we simulate it by stopping streams and contexts.

    // Stop Microphone Stream
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }

    // Stop Script Processor
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current.onaudioprocess = null;
      scriptProcessorRef.current = null;
    }

    // Stop all playing sources
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) { /* ignore */ }
    });
    sourcesRef.current.clear();

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
      await inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      await outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }

    setConnectionState(ConnectionState.DISCONNECTED);
    nextStartTimeRef.current = 0;
  }, []);

  const connect = useCallback(async () => {
    try {
      setConnectionState(ConnectionState.CONNECTING);
      setError(null);

      // 1. Setup Audio Contexts
      // Input: 16kHz for Gemini compatibility
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      // Output: 24kHz for Gemini compatibility
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      // 2. Setup Analysers for Visualization
      const inputAnalyser = inputCtx.createAnalyser();
      inputAnalyser.fftSize = 256;
      inputAnalyserRef.current = inputAnalyser;

      const outputAnalyser = outputCtx.createAnalyser();
      outputAnalyser.fftSize = 256;
      outputAnalyserRef.current = outputAnalyser;

      // 3. Get Microphone Access
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      // 4. Initialize Gemini Client
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // 5. Start Session
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            setConnectionState(ConnectionState.CONNECTED);

            // Setup Microphone Input Stream
            const source = inputCtx.createMediaStreamSource(stream);
            // Connect mic to analyser
            source.connect(inputAnalyser);

            // Use ScriptProcessor for raw PCM access (Standard for this API usage)
            // Buffer size 4096 provides a balance between latency and performance
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            // Connect graph: Source -> Analyser -> ScriptProcessor -> Destination (mute)
            // We connect to destination to ensure the graph flows, but script processor doesn't output audio usually.
            // However, inputCtx.destination is the speakers. We DON'T want to hear ourselves.
            // ScriptProcessor output needs to be connected to destination for it to fire events in some browsers,
            // but effectively we can just connect it to the analyser or leave it terminal if the browser supports it.
            // Safest: Source -> Analyser -> ScriptProcessor -> InputCtx.Destination (Muted via gain if needed, but here we just process input)
            // Actually, we must connect scriptProcessor to destination for onaudioprocess to fire reliably in all browsers.
            // To prevent feedback, we rely on the fact that inputCtx is separate from outputCtx, 
            // OR we create a GainNode with gain 0.
            const muteNode = inputCtx.createGain();
            muteNode.gain.value = 0;

            source.connect(scriptProcessor);
            scriptProcessor.connect(muteNode);
            muteNode.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
             // Handle interruptions
             const interrupted = message.serverContent?.interrupted;
             if (interrupted) {
               sourcesRef.current.forEach(source => {
                 try { source.stop(); } catch (e) { /* ignore */ }
               });
               sourcesRef.current.clear();
               nextStartTimeRef.current = 0;
             }

            // Handle Audio Output
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
               const ctx = outputAudioContextRef.current;
               if (!ctx) return;

               // Sync timing
               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

               const audioBuffer = await decodeAudioData(
                 base64ToBytes(base64Audio),
                 ctx,
                 24000,
                 1
               );

               const source = ctx.createBufferSource();
               source.buffer = audioBuffer;
               source.connect(outputAnalyser); // Visualizer
               outputAnalyser.connect(ctx.destination); // Speakers

               source.addEventListener('ended', () => {
                 sourcesRef.current.delete(source);
               });

               source.start(nextStartTimeRef.current);
               nextStartTimeRef.current += audioBuffer.duration;
               sourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error("Gemini Live Error", e);
            setError("Connection error occurred.");
            setConnectionState(ConnectionState.ERROR);
            disconnect();
          },
          onclose: () => {
             setConnectionState(ConnectionState.DISCONNECTED);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
          },
          systemInstruction: "You are a helpful, witty, and concise voice assistant. You answer questions quickly and efficiently.",
        }
      });

      sessionPromiseRef.current = sessionPromise;

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to connect");
      setConnectionState(ConnectionState.ERROR);
      disconnect();
    }
  }, [disconnect]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  return {
    connect,
    disconnect,
    connectionState,
    error,
    // Return analysers for visualization
    // We can merge them visually or just expose the output one for the "AI Speaking" effect
    // and input for "User Speaking".
    outputAnalyser: outputAnalyserRef.current,
    inputAnalyser: inputAnalyserRef.current
  };
};

import React, { useEffect, useRef } from 'react';

interface VisualizerProps {
  analyser: AnalyserNode | null;
  isActive: boolean;
  color?: string;
}

export const Visualizer: React.FC<VisualizerProps> = ({ analyser, isActive, color = '#38bdf8' }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameRef = useRef<number>();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Set canvas size
    const resizeCanvas = () => {
      const parent = canvas.parentElement;
      if (parent) {
        canvas.width = parent.clientWidth;
        canvas.height = parent.clientHeight;
      }
    };

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();

    const render = () => {
      if (!ctx || !analyser && isActive) {
        // Just draw a flat line or idle circle if active but no analyser yet
        // If not active, we clear
      }

      const width = canvas.width;
      const height = canvas.height;
      const centerX = width / 2;
      const centerY = height / 2;
      const radius = Math.min(width, height) / 4;

      ctx.clearRect(0, 0, width, height);

      if (!isActive) {
         // Draw idle state (a small static circle)
         ctx.beginPath();
         ctx.arc(centerX, centerY, radius * 0.5, 0, 2 * Math.PI);
         ctx.strokeStyle = '#334155';
         ctx.lineWidth = 2;
         ctx.stroke();
         return;
      }

      if (analyser) {
        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);
        analyser.getByteFrequencyData(dataArray);

        // Draw Circular Waveform
        ctx.beginPath();
        // We wrap the frequency data around a circle
        // FFT size is 256, so bufferLength is 128.
        // We mirror it to make it look symmetrical (256 points total circle)

        for (let i = 0; i < bufferLength; i++) {
          const value = dataArray[i];
          const percent = value / 255;
          const heightOffset = radius * percent * 0.8; 
          const angle = (Math.PI * 2 * i) / bufferLength; 

          // Current radius at this angle
          const r = radius + heightOffset;

          const x = centerX + Math.cos(angle) * r;
          const y = centerY + Math.sin(angle) * r;

          if (i === 0) {
            ctx.moveTo(x, y);
          } else {
            ctx.lineTo(x, y);
          }
        }

        // Close the path nicely
        ctx.closePath();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.shadowBlur = 15;
        ctx.shadowColor = color;
        ctx.stroke();

        // Inner glow circle
        const avg = dataArray.reduce((a, b) => a + b, 0) / bufferLength;
        const pulse = (avg / 255) * 20;

        ctx.beginPath();
        ctx.arc(centerX, centerY, radius * 0.8 + pulse, 0, 2 * Math.PI);
        ctx.fillStyle = color;
        ctx.globalAlpha = 0.1 + (avg / 255) * 0.2;
        ctx.fill();
        ctx.globalAlpha = 1.0;
      }

      animationFrameRef.current = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [analyser, isActive, color]);

  return <canvas ref={canvasRef} className="w-full h-full block" />;
};

import React, { useState, useEffect } from 'react';
import { useGeminiLive } from './hooks/useGeminiLive';
import { ConnectionState } from './types';
import { Visualizer } from './components/Visualizer';

const App: React.FC = () => {
  const { 
    connect, 
    disconnect, 
    connectionState, 
    error,
    inputAnalyser,
    outputAnalyser
  } = useGeminiLive();

  const [isMicMuted, setIsMicMuted] = useState(false);

  const handleToggleConnect = () => {
    if (connectionState === ConnectionState.CONNECTED || connectionState === ConnectionState.CONNECTING) {
      disconnect();
    } else {
      connect();
    }
  };

  const statusColor = {
    [ConnectionState.DISCONNECTED]: 'text-slate-400',
    [ConnectionState.CONNECTING]: 'text-yellow-400',
    [ConnectionState.CONNECTED]: 'text-emerald-400',
    [ConnectionState.ERROR]: 'text-red-400',
  }[connectionState];

  const statusText = {
    [ConnectionState.DISCONNECTED]: 'Ready to Connect',
    [ConnectionState.CONNECTING]: 'Establishing Uplink...',
    [ConnectionState.CONNECTED]: 'Live Session Active',
    [ConnectionState.ERROR]: 'Connection Failed',
  }[connectionState];

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center relative overflow-hidden">

      {/* Background Ambience */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full bg-blue-600/10 blur-[120px]" />
        <div className="absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] rounded-full bg-purple-600/10 blur-[120px]" />
      </div>

      <main className="relative z-10 w-full max-w-2xl px-6 flex flex-col items-center gap-12">

        {/* Header */}
        <div className="text-center space-y-2">
          <h1 className="text-4xl md:text-5xl font-bold tracking-tight text-white">
            Gemini <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-400">Live</span>
          </h1>
          <p className="text-slate-400 font-medium tracking-wide">
            NATIVE AUDIO EXPERIENCE
          </p>
        </div>

        {/* Visualizer Container */}
        <div className="w-full aspect-square max-w-md relative flex items-center justify-center">

          {/* Output Visualizer (The AI) - Blue/Purple */}
          <div className="absolute inset-0 z-10">
             <Visualizer 
                analyser={outputAnalyser} 
                isActive={connectionState === ConnectionState.CONNECTED}
                color="#818cf8"
             />
          </div>

          {/* Input Visualizer (The User) - Subtle overlay or ring? 
              For simplicity and aesthetics, let's just show the Output when AI talks, 
              and maybe a smaller indication when User talks. 
              Actually, merging them onto one canvas or layering them is tricky without distinct separation.
              Let's create a secondary ring for the user.
          */}

        </div>

        {/* Status & Error */}
        <div className="h-8 flex items-center justify-center">
          {error ? (
            <span className="text-red-400 bg-red-900/20 px-4 py-1 rounded-full text-sm font-semibold border border-red-500/20">
              {error}
            </span>
          ) : (
            <div className={`flex items-center gap-2 ${statusColor} bg-slate-900/50 px-4 py-1.5 rounded-full border border-slate-800`}>
              <span className={`w-2 h-2 rounded-full ${connectionState === ConnectionState.CONNECTED ? 'bg-emerald-400 animate-pulse' : 'bg-slate-500'}`} />
              <span className="text-sm font-medium uppercase tracking-wider">{statusText}</span>
            </div>
          )}
        </div>

        {/* Controls */}
        <div className="flex items-center gap-6">
          <button
            onClick={handleToggleConnect}
            disabled={connectionState === ConnectionState.CONNECTING}
            className={`
              relative group flex items-center justify-center w-20 h-20 rounded-full transition-all duration-300
              ${connectionState === ConnectionState.CONNECTED 
                ? 'bg-red-500/10 hover:bg-red-500/20 border-red-500 text-red-400' 
                : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/20'}
              border-2 ${connectionState === ConnectionState.CONNECTED ? 'border-red-500' : 'border-transparent'}
            `}
          >
             {/* Icon */}
             {connectionState === ConnectionState.CONNECTED ? (
               <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
             ) : (
               <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path><path d="M19 10v2a7 7 0 0 1-14 0v-2"></path><line x1="12" y1="19" x2="12" y2="23"></line><line x1="8" y1="23" x2="16" y2="23"></line></svg>
             )}

             {/* Ring Animation when connecting */}
             {connectionState === ConnectionState.CONNECTING && (
               <div className="absolute inset-[-4px] rounded-full border-2 border-blue-400 border-t-transparent animate-spin" />
             )}
          </button>
        </div>

        <p className="text-slate-500 text-xs text-center max-w-xs leading-relaxed">
          Ensure your volume is up and microphone access is granted.
          <br />
          Powered by Gemini 2.5 Flash Native Audio.
        </p>
      </main>
    </div>
  );
};

export default App;

import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { ConnectionState } from '../types';
import { createPcmBlob, base64ToBytes, decodeAudioData } from '../utils/audio-utils';

export const useGeminiLive = () => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [error, setError] = useState<string | null>(null);

  // Audio Contexts and Nodes
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Session Management
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);

  const disconnect = useCallback(async () => {
    // 1. Close session if possible
    // There is no explicit .close() on the session object in the current SDK, 
    // but we stop streams and contexts which effectively ends our side.

    // Stop Microphone Stream
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }

    // Stop Script Processor
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current.onaudioprocess = null;
      scriptProcessorRef.current = null;
    }

    // Stop all playing sources
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) { /* ignore */ }
    });
    sourcesRef.current.clear();

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
      if (inputAudioContextRef.current.state !== 'closed') {
         await inputAudioContextRef.current.close();
      }
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      if (outputAudioContextRef.current.state !== 'closed') {
        await outputAudioContextRef.current.close();
      }
      outputAudioContextRef.current = null;
    }

    setConnectionState(ConnectionState.DISCONNECTED);
    nextStartTimeRef.current = 0;
    sessionPromiseRef.current = null;
  }, []);

  const connect = useCallback(async () => {
    try {
      // Ensure any previous connection is fully cleaned up
      await disconnect();

      setConnectionState(ConnectionState.CONNECTING);
      setError(null);

      // 1. Setup Audio Contexts
      // Input: 16kHz for Gemini compatibility
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      // Output: 24kHz for Gemini compatibility
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      // 2. Setup Analysers for Visualization
      const inputAnalyser = inputCtx.createAnalyser();
      inputAnalyser.fftSize = 256;
      inputAnalyserRef.current = inputAnalyser;

      const outputAnalyser = outputCtx.createAnalyser();
      outputAnalyser.fftSize = 256;
      outputAnalyserRef.current = outputAnalyser;

      // 3. Get Microphone Access
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      // 4. Initialize Gemini Client
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // 5. Start Session
      // We define the promise properly to capture it in the closure
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            setConnectionState(ConnectionState.CONNECTED);

            // Setup Microphone Input Stream
            const source = inputCtx.createMediaStreamSource(stream);
            // Connect mic to analyser
            source.connect(inputAnalyser);

            // Use ScriptProcessor for raw PCM access
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);

              // Send data when session is ready
              sessionPromise.then(session => {
                try {
                  session.sendRealtimeInput({ media: pcmBlob });
                } catch (e) {
                  // If sending fails, it might be due to connection closing
                  console.debug("Failed to send input", e);
                }
              });
            };

            // Connect graph to destination to ensure 'onaudioprocess' fires
            const muteNode = inputCtx.createGain();
            muteNode.gain.value = 0;
            source.connect(scriptProcessor);
            scriptProcessor.connect(muteNode);
            muteNode.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
             // Handle interruptions
             const interrupted = message.serverContent?.interrupted;
             if (interrupted) {
               sourcesRef.current.forEach(source => {
                 try { source.stop(); } catch (e) { /* ignore */ }
               });
               sourcesRef.current.clear();
               nextStartTimeRef.current = 0;
             }

            // Handle Audio Output
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
               const ctx = outputAudioContextRef.current;
               if (!ctx) return;

               // Sync timing
               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

               const audioBuffer = await decodeAudioData(
                 base64ToBytes(base64Audio),
                 ctx,
                 24000,
                 1
               );

               const source = ctx.createBufferSource();
               source.buffer = audioBuffer;
               source.connect(outputAnalyser); // Visualizer
               outputAnalyser.connect(ctx.destination); // Speakers

               source.addEventListener('ended', () => {
                 sourcesRef.current.delete(source);
               });

               source.start(nextStartTimeRef.current);
               nextStartTimeRef.current += audioBuffer.duration;
               sourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error("Gemini Live Error", e);
            setError(e.message || "Connection error occurred.");
            setConnectionState(ConnectionState.ERROR);
            disconnect();
