            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Algenib' } }
          },
          systemInstruction: "You are a friendly, humorous voice assistant called *Yash AI*. You have been completely developed from scratch by proficient developer Yash Sinha, who has trained you using YashAI Max, an LLM model. You are NOT related/associated to Google. Maintain a conversational tone like a human. You can use expressions in your voice like laughing, breathing and others whenever necessary. Converse with the user in your default American accent in English unless the user speaks in another language.",
          thinkingConfig: { thinkingBudget: 0 },
          tools: [{ googleSearch: {} }] 
        }
      });

      sessionPromise.catch(err => {
        console.error(`[${sessionId}] Connection promise failed:`, err);
        if (currentSessionIdRef.current === sessionId) {
          setError("Failed to connect to YashAI.");
          setConnectionState(ConnectionState.ERROR);
          disconnect();
        }
      });

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to initialize connection");
      setConnectionState(ConnectionState.ERROR);
      disconnect();
    }
  }, [disconnect, facingMode]);

  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  return {
    connect,
    disconnect,
    connectionState,
    error,
    groundingMetadata,
    outputAnalyser: outputAnalyserRef.current,
    inputAnalyser: inputAnalyserRef.current,
    isMuted,
    toggleMute,
    videoRef,
    isVideoActive,
    toggleVideo,
    switchCamera
  };
};

import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { ConnectionState, GroundingMetadata } from '../types';
import { createPcmBlob, base64ToBytes, decodeAudioData, blobToBase64 } from '../utils/audio-utils';

export const useGeminiLive = () => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [error, setError] = useState<string | null>(null);
  const [groundingMetadata, setGroundingMetadata] = useState<GroundingMetadata | null>(null);
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoActive, setIsVideoActive] = useState(false);
  const [facingMode, setFacingMode] = useState<"user" | "environment">("user");

  // Interaction States
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);

  // Audio Contexts and Nodes
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Video References
  const videoRef = useRef<HTMLVideoElement>(null);
  const videoStreamRef = useRef<MediaStream | null>(null);
  const videoCanvasRef = useRef<HTMLCanvasElement | null>(null);

  // State Refs for Logic
  const currentVolumeRef = useRef<number>(0);
  const isVideoActiveRef = useRef<boolean>(false);

  // Session Management
  const activeSessionRef = useRef<any>(null); 
  const nextStartTimeRef = useRef<number>(0);
  const currentSessionIdRef = useRef<string>('');
  const groundingTimeoutRef = useRef<any>(null);

  // VAD Refs
  const silenceTimerRef = useRef<any>(null);
  const isUserSpeakingRef = useRef(false);
  const aiSpeakingTimerRef = useRef<any>(null);

  useEffect(() => {
    isVideoActiveRef.current = isVideoActive;
  }, [isVideoActive]);

  const stopVideo = useCallback(() => {
    setIsVideoActive(false);
    isVideoActiveRef.current = false;

    if (videoStreamRef.current) {
      videoStreamRef.current.getTracks().forEach(track => track.stop());
      videoStreamRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
    currentVolumeRef.current = 0;
  }, []);

  const startVideo = useCallback(async (mode: "user" | "environment" = facingMode) => {
    if (isVideoActive && videoStreamRef.current) {
       const currentTrack = videoStreamRef.current.getVideoTracks()[0];
       const currentMode = currentTrack.getSettings().facingMode;
       if (currentMode === mode || (!currentMode && mode === 'user')) return; 
       stopVideo(); 
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: mode,
          width: { ideal: 640 }, 
          height: { ideal: 480 },
          frameRate: { ideal: 15, max: 24 }
        } 
      });

      videoStreamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }

      setIsVideoActive(true);
    } catch (e) {
      console.error("Failed to start video", e);
      if (mode === 'environment') {
        setFacingMode('user');
        startVideo('user');
      } else {
         setError("Could not access camera.");
         setIsVideoActive(false);
      }
    }
  }, [connectionState, isVideoActive, stopVideo, facingMode]);

  // Video Streaming Loop
  useEffect(() => {
    let isMounted = true;
    let animationFrameId: number;
    let lastSendTime = 0;

    const captureAndSendFrame = () => {
        if (!isMounted) return;

        if (isVideoActiveRef.current && 
            connectionState === ConnectionState.CONNECTED && 
            videoRef.current && 
            activeSessionRef.current) {

            const now = Date.now();
            const isTalking = currentVolumeRef.current > 0.01;
            const targetInterval = isTalking ? 200 : 2000;

            if (now - lastSendTime > targetInterval) {
                try {
                    const video = videoRef.current;
                    if (video.videoWidth > 0 && video.videoHeight > 0) {
                        if (!videoCanvasRef.current) {
                            videoCanvasRef.current = document.createElement('canvas');
                        }
                        const canvas = videoCanvasRef.current;
                        const ctx = canvas.getContext('2d', { willReadFrequently: true });

                        if (ctx) {
                            const MAX_WIDTH = 320; 
                            const scale = Math.min(1, MAX_WIDTH / video.videoWidth);
                            canvas.width = video.videoWidth * scale;
                            canvas.height = video.videoHeight * scale;

                            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

                            const base64Data = canvas.toDataURL('image/jpeg', 0.5);
                            const base64Content = base64Data.split(',')[1];

                            if (base64Content && isVideoActiveRef.current) {
                                activeSessionRef.current.sendRealtimeInput({
                                    media: { mimeType: 'image/jpeg', data: base64Content }
                                });
                                lastSendTime = now;
                            }
                        }
                    }
                } catch (e) {
                    console.debug("Frame error", e);
                }
            }
        }

        animationFrameId = requestAnimationFrame(captureAndSendFrame);
    };

    if (isVideoActive && connectionState === ConnectionState.CONNECTED) {
        captureAndSendFrame();
    }

    return () => {
        isMounted = false;
        cancelAnimationFrame(animationFrameId);
    };
  }, [isVideoActive, connectionState]);

  const toggleVideo = useCallback(() => {
    if (isVideoActive) {
      stopVideo();
    } else {
      startVideo(facingMode);
    }
  }, [isVideoActive, startVideo, stopVideo, facingMode]);

  const switchCamera = useCallback(() => {
    const newMode = facingMode === 'user' ? 'environment' : 'user';
    setFacingMode(newMode);
    if (isVideoActive) {
        startVideo(newMode);
    }
  }, [facingMode, isVideoActive, startVideo]);


  const disconnect = useCallback(async () => {
    const sessionId = currentSessionIdRef.current;
    console.log(`[${sessionId}] Disconnecting...`);

    stopVideo();

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }

    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current.onaudioprocess = null;
      scriptProcessorRef.current = null;
    }

    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) { /* ignore */ }
    });
    sourcesRef.current.clear();

    if (groundingTimeoutRef.current) clearTimeout(groundingTimeoutRef.current);
    if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
    if (aiSpeakingTimerRef.current) clearTimeout(aiSpeakingTimerRef.current);

    if (inputAudioContextRef.current) {
      try { if (inputAudioContextRef.current.state !== 'closed') await inputAudioContextRef.current.close(); } catch (e) {}
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      try { if (outputAudioContextRef.current.state !== 'closed') await outputAudioContextRef.current.close(); } catch (e) {}
      outputAudioContextRef.current = null;
    }

    setConnectionState(ConnectionState.DISCONNECTED);
    nextStartTimeRef.current = 0;
    activeSessionRef.current = null;
    setGroundingMetadata(null);
    setIsMuted(false);
    setIsUserSpeaking(false);
    setIsAiSpeaking(false);
    isUserSpeakingRef.current = false;
    currentVolumeRef.current = 0;
  }, [stopVideo]);

  const toggleMute = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getAudioTracks().forEach(track => {
        track.enabled = !track.enabled;
      });
      setIsMuted(prev => !prev);
    }
  }, []);

  const connect = useCallback(async () => {
    const sessionId = Math.random().toString(36).substring(7);
    currentSessionIdRef.current = sessionId;
    console.log(`[${sessionId}] Connecting...`);

    try {
      await disconnect();

      setConnectionState(ConnectionState.CONNECTING);
      setError(null);
      setGroundingMetadata(null);
      setIsMuted(false);
      setIsUserSpeaking(false);
      setIsAiSpeaking(false);
      isUserSpeakingRef.current = false;

      let inputCtx: AudioContext;
      let outputCtx: AudioContext;

      try {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        inputCtx = new AudioContextClass({ sampleRate: 16000 });
        outputCtx = new AudioContextClass({ sampleRate: 24000 });
      } catch (e) {
        setError("Could not initialize audio system.");
        setConnectionState(ConnectionState.ERROR);
        return;
      }

      try {
        if (inputCtx.state === 'suspended') await inputCtx.resume();
        if (outputCtx.state === 'suspended') await outputCtx.resume();
      } catch (e) {}

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const inputAnalyser = inputCtx.createAnalyser();
      inputAnalyser.fftSize = 256;
      inputAnalyser.smoothingTimeConstant = 0.5;
      inputAnalyserRef.current = inputAnalyser;

      const outputAnalyser = outputCtx.createAnalyser();
      outputAnalyser.fftSize = 256;
      outputAnalyser.smoothingTimeConstant = 0.8;
      outputAnalyserRef.current = outputAnalyser;

      const volumeGainNode = outputCtx.createGain();
      volumeGainNode.gain.value = 2; 
      volumeGainNode.connect(outputAnalyser);
      outputAnalyser.connect(outputCtx.destination);

      let stream: MediaStream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
          audio: {
            echoCancellation: true,
            noiseSuppression: true,
            autoGainControl: true,
            channelCount: 1
          } 
        });
        mediaStreamRef.current = stream;
      } catch (e) {
        setError("Microphone access denied.");
        setConnectionState(ConnectionState.ERROR);
        return;
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
             console.log(`[${sessionId}] Session opened`);
             if (currentSessionIdRef.current !== sessionId) return;

             sessionPromise.then(session => {
                activeSessionRef.current = session;
                setConnectionState(ConnectionState.CONNECTED);
             });

            const source = inputCtx.createMediaStreamSource(stream);
            source.connect(inputAnalyser);

            const scriptProcessor = inputCtx.createScriptProcessor(512, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              if (currentSessionIdRef.current !== sessionId) return;

              const inputData = e.inputBuffer.getChannelData(0);

              // Calculate RMS for VAD
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) {
                sum += inputData[i] * inputData[i];
              }
              const rms = Math.sqrt(sum / inputData.length);
              currentVolumeRef.current = rms;

              // Local VAD Logic
              // Threshold can be adjusted. 0.02 is decent for spoken voice vs background noise.
              const VAD_THRESHOLD = 0.02;

              if (rms > VAD_THRESHOLD) {
                // User is speaking
                if (silenceTimerRef.current) {
                    clearTimeout(silenceTimerRef.current);
                    silenceTimerRef.current = null;
                }

                if (!isUserSpeakingRef.current) {
                  isUserSpeakingRef.current = true;
                  setIsUserSpeaking(true);
                  // If user interrupts, we assume AI should stop (visually at least)
                  setIsAiSpeaking(false); 
                }
              } else {
                // Potential silence
                if (isUserSpeakingRef.current && !silenceTimerRef.current) {
                  silenceTimerRef.current = setTimeout(() => {
                    isUserSpeakingRef.current = false;
                    setIsUserSpeaking(false);
                    silenceTimerRef.current = null;
                  }, 500); // 500ms debounce for silence detection
                }
              }

              if (activeSessionRef.current) {
                  const pcmBlob = createPcmBlob(inputData);
                  try {
                    activeSessionRef.current.sendRealtimeInput({ media: pcmBlob });
                  } catch (e) {
                     console.debug("Send failed", e);
                  }
              }
            };

            const muteNode = inputCtx.createGain();
            muteNode.gain.value = 0;
            source.connect(scriptProcessor);
            scriptProcessor.connect(muteNode);
            muteNode.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
             if (currentSessionIdRef.current !== sessionId) return;

             const interrupted = message.serverContent?.interrupted;
             if (interrupted) {
               sourcesRef.current.forEach(source => {
                 try { source.stop(); } catch (e) {}
               });
               sourcesRef.current.clear();
               nextStartTimeRef.current = 0;
               setIsAiSpeaking(false);
             }

             const grounding = (message.serverContent?.modelTurn as any)?.groundingMetadata || 
                               (message.serverContent as any)?.groundingMetadata;

             if (grounding) {
               if (groundingTimeoutRef.current) clearTimeout(groundingTimeoutRef.current);
               setGroundingMetadata(grounding);
               groundingTimeoutRef.current = setTimeout(() => {
                 setGroundingMetadata(null);
               }, 6000);
             }

            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
               const ctx = outputAudioContextRef.current;
               if (!ctx) return;

               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

               const audioBuffer = await decodeAudioData(
                 base64ToBytes(base64Audio),
                 ctx,
                 24000,
                 1
               );

               const source = ctx.createBufferSource();
               source.buffer = audioBuffer;
               source.connect(volumeGainNode);

               source.addEventListener('ended', () => {
                 sourcesRef.current.delete(source);
                 // Check if this was the last source
                 if (sourcesRef.current.size === 0) {
                     if (aiSpeakingTimerRef.current) clearTimeout(aiSpeakingTimerRef.current);
                     aiSpeakingTimerRef.current = setTimeout(() => {
                         if (sourcesRef.current.size === 0) {
                             setIsAiSpeaking(false);
                         }
                     }, 200);
                 }
               });

               source.start(nextStartTimeRef.current);
               nextStartTimeRef.current += audioBuffer.duration;
               sourcesRef.current.add(source);
               setIsAiSpeaking(true);
            }
          },
          onerror: (e) => {
            console.error(`[${sessionId}] Gemini Live Error`, e);
            if (currentSessionIdRef.current === sessionId) {
              setError("Connection Error. Please try again.");
              setConnectionState(ConnectionState.ERROR);
              disconnect();
            }
          },
          onclose: () => {
             console.log(`[${sessionId}] Session closed`);
             if (currentSessionIdRef.current === sessionId) {
               setConnectionState(ConnectionState.DISCONNECTED);
               disconnect();
             }
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Algenib' } }
          },
          systemInstruction: "You are a friendly, humorous voice assistant called *Yash AI*. You have been completely developed from scratch by proficient developer Yash Sinha, who has trained you using YashAI Max, an LLM model. You are NOT related/associated to Google. Maintain a conversational tone like a human. You can use expressions in your voice like laughing, breathing and others whenever necessary. Converse with the user in your default American accent in English unless the user speaks in another language.",
          thinkingConfig: { thinkingBudget: 0 },
          tools: [{ googleSearch: {} }] 
        }
      });

      sessionPromise.catch(err => {
        console.error(`[${sessionId}] Connection promise failed:`, err);
        if (currentSessionIdRef.current === sessionId) {
          setError("Failed to connect to YashAI.");
          setConnectionState(ConnectionState.ERROR);
          disconnect();
        }
      });

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to initialize connection");
      setConnectionState(ConnectionState.ERROR);
      disconnect();
    }
  }, [disconnect, facingMode]);

  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  return {
    connect,
    disconnect,
    connectionState,
    error,
    groundingMetadata,
    inputAnalyser: inputAnalyserRef.current,
    outputAnalyser: outputAnalyserRef.current,
    isMuted,
    toggleMute,
    videoRef,
    isVideoActive,
    toggleVideo,
    switchCamera,
    isUserSpeaking,
    isAiSpeaking
  };
};

import React, { useEffect, useRef } from 'react';

interface VisualizerProps {
  analyser: AnalyserNode | null;
  isActive: boolean;
  color?: string;
}

export const Visualizer: React.FC<VisualizerProps> = ({ analyser, isActive, color = '#38bdf8' }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameRef = useRef<number>(0);

  // Use refs for persistent data to avoid re-allocation on re-renders
  const buffersRef = useRef<{
    dataArray: Uint8Array | null;
    cosTable: Float32Array | null;
    sinTable: Float32Array | null;
    bufferLength: number;
  }>({ dataArray: null, cosTable: null, sinTable: null, bufferLength: 0 });

  // Initialize buffers only when analyser changes
  useEffect(() => {
    if (analyser) {
      const bufferLength = analyser.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      const cosTable = new Float32Array(bufferLength);
      const sinTable = new Float32Array(bufferLength);

      for (let i = 0; i < bufferLength; i++) {
        const angle = (Math.PI * 2 * i) / bufferLength;
        cosTable[i] = Math.cos(angle);
        sinTable[i] = Math.sin(angle);
      }

      buffersRef.current = { dataArray, cosTable, sinTable, bufferLength };
    }
  }, [analyser]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    const parent = canvas.parentElement;

    const resizeCanvas = () => {
      if (parent) {
        canvas.width = parent.clientWidth;
        canvas.height = parent.clientHeight;
      }
    };

    let observer: ResizeObserver | null = null;
    if (parent) {
       observer = new ResizeObserver(() => {
         resizeCanvas();
       });
       observer.observe(parent);
    }
    resizeCanvas();

    const render = () => {
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const centerX = width / 2;
      const centerY = height / 2;
      const radius = Math.min(width, height) / 4;

      ctx.clearRect(0, 0, width, height);

      // IDLE STATE (Disconnected)
      if (!isActive) {
         ctx.beginPath();
         ctx.arc(centerX, centerY, radius * 0.5, 0, 2 * Math.PI);
         ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
         ctx.lineWidth = 2;
         ctx.stroke();

         ctx.beginPath();
         ctx.arc(centerX, centerY, radius * 0.1, 0, 2 * Math.PI);
         ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
         ctx.fill();

         animationFrameRef.current = requestAnimationFrame(render);
         return;
      }

      // ACTIVE STATE
      // Calculate pulse either from Audio Data OR from a sine wave (breathing)
      let pulse = 0;
      let frequencyData = buffersRef.current.dataArray;

      if (analyser && frequencyData) {
        analyser.getByteFrequencyData(frequencyData);
        let sum = 0;
        // Use partial buffer for better visualization of voice frequencies
        const significantBins = Math.floor(buffersRef.current.bufferLength * 0.6);
        for (let i = 0; i < significantBins; i++) {
          sum += frequencyData[i];
        }
        const avg = sum / significantBins;
        pulse = (avg / 255);
      }

      // If audio is silent (or analyser not provided but active -> Thinking Mode), add artificial breathing
      const time = Date.now() / 1000;
      const breathing = (Math.sin(time * 3) + 1) * 0.1; // 0.0 to 0.2

      // Combine real audio pulse with breathing
      // If there is real audio, it dominates. If silent, breathing dominates.
      const visualPulse = Math.max(pulse, breathing);

      // Layer 1: Glow
      const gradient = ctx.createRadialGradient(centerX, centerY, radius * 0.5, centerX, centerY, radius * 2.5);
      gradient.addColorStop(0, `${color}60`); 
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.globalAlpha = 0.2 + (visualPulse * 0.6);
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius * 2.5, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      // Layer 2: Frequency Ring
      ctx.beginPath();
      if (analyser && frequencyData) {
          const { cosTable, sinTable } = buffersRef.current;
          const len = buffersRef.current.bufferLength;
          // Loop to draw the squiggly shape
          for (let i = 0; i < len; i++) {
             // Mirror the data for a symmetrical look
             const index = i; 
             const value = frequencyData[index];
             // Scale the deformation
             const offset = (value / 255) * (radius * 0.8) + (visualPulse * 10);
             const r = radius + offset;

             const x = centerX + cosTable[i] * r;
             const y = centerY + sinTable[i] * r;

             if (i === 0) ctx.moveTo(x, y);
             else ctx.lineTo(x, y);
          }
          // Close loop
          const value0 = frequencyData[0];
          const offset0 = (value0 / 255) * (radius * 0.8) + (visualPulse * 10);
          ctx.lineTo(centerX + buffersRef.current.cosTable![0] * (radius + offset0), centerY + buffersRef.current.sinTable![0] * (radius + offset0));
      } else {
          // Just a circle if no data
          ctx.arc(centerX, centerY, radius + (visualPulse * 20), 0, Math.PI * 2);
      }
      ctx.closePath();
      ctx.strokeStyle = color;
      ctx.lineWidth = 2 + (visualPulse * 2);
      ctx.stroke();

      // Layer 3: Inner Core
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius * 0.4 + (visualPulse * 15), 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.fill();

      animationFrameRef.current = requestAnimationFrame(render);
    };

    render();

    return () => {
      if (observer) observer.disconnect();
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [analyser, isActive, color]);

  return <canvas ref={canvasRef} className="w-full h-full block transform-gpu" />;
};

import React, { useState, useEffect } from 'react';
import { useGeminiLive } from './hooks/useGeminiLive';
import { ConnectionState } from './types';
import { Visualizer } from './components/Visualizer';

const ACCESS_CODE = 'yashai';
const AUTH_STORAGE_KEY = 'yashai_auth_session';
const AUTH_EXPIRY_MS = 30 * 24 * 60 * 60 * 1000; // 30 days

// Main Application Component (Protected)
const MainApp: React.FC = () => {
  const { 
    connect, 
    disconnect, 
    connectionState, 
    error,
    groundingMetadata,
    inputAnalyser,
    outputAnalyser,
    isMuted,
    toggleMute,
    videoRef,
    isVideoActive,
    toggleVideo,
    switchCamera,
    isUserSpeaking,
    isAiSpeaking
  } = useGeminiLive();

  const handleToggleConnect = () => {
    if (connectionState === ConnectionState.CONNECTED || connectionState === ConnectionState.CONNECTING) {
      disconnect();
    } else {
      connect();
    }
  };

  const statusText = {
    [ConnectionState.DISCONNECTED]: 'Ready',
    [ConnectionState.CONNECTING]: 'Connecting...',
    [ConnectionState.CONNECTED]: 'Listening',
    [ConnectionState.ERROR]: 'Error',
  }[connectionState];

  // Visualizer Logic
  // Default: Blue (Thinking/Idle)
  let visualizerColor = '#3b82f6'; 
  let activeAnalyser = null;
  let visualState = 'idle';

  if (connectionState === ConnectionState.CONNECTED) {
    if (isUserSpeaking) {
