// Authentication Wrapper
const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    try {
      const stored = localStorage.getItem(AUTH_STORAGE_KEY);
      if (stored) {
        const { timestamp } = JSON.parse(stored);
        if (Date.now() - timestamp < AUTH_EXPIRY_MS) {
          return true;
        }
      }
    } catch (e) {
      console.error("Auth storage read error", e);
    }
    return false;
  });

  const [passcodeInput, setPasscodeInput] = useState('');
  const [authError, setAuthError] = useState('');

  if (!isAuthenticated) {
    return (
        <div className="min-h-screen bg-[#0A0A0A] text-white font-sans flex flex-col items-center justify-center relative overflow-hidden selection:bg-blue-500/30">
            {/* Background - Consistent with Main App */}
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] rounded-full bg-blue-900/10 blur-[150px] animate-pulse" />
                <div className="absolute bottom-[-20%] right-[-10%] w-[60%] h-[60%] rounded-full bg-indigo-900/10 blur-[150px] animate-pulse" />
            </div>

            <div className="z-10 w-full max-w-md p-8 bg-white/5 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl flex flex-col gap-6 transform-gpu transition-all">
                <div className="text-center">
                    <div className="w-12 h-12 rounded-full bg-gradient-to-tr from-blue-500 to-indigo-500 mx-auto mb-4 shadow-lg shadow-indigo-500/20"></div>
                    <h1 className="text-2xl font-bold tracking-tight text-white mb-2">YashAI Voice</h1>
                    <p className="text-slate-400 text-sm">Restricted Access</p>
                </div>

                <form 
                    onSubmit={(e) => {
                        e.preventDefault();
                        if (passcodeInput.toLowerCase().trim() === ACCESS_CODE) {
                            setIsAuthenticated(true);
                            setAuthError('');
                            localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify({
                              timestamp: Date.now()
                            }));
                        } else {
                            setAuthError('Access denied. Invalid code.');
                            setPasscodeInput('');
                        }
                    }}
                    className="flex flex-col gap-4"
                >
                    <div>
                        <input 
                            type="password" 
                            value={passcodeInput}
                            onChange={(e) => setPasscodeInput(e.target.value)}
                            placeholder="Enter access code"
                            className="w-full bg-black/20 border border-white/10 rounded-lg px-4 py-3 text-center text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all"
                            autoFocus
                        />
                        {authError && <p className="text-red-400 text-xs text-center mt-2">{authError}</p>}
                    </div>

                    <button 
                        type="submit"
                        className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-medium py-3 rounded-lg transition-colors shadow-lg shadow-indigo-500/20"
                    >
                        Enter
                    </button>
                </form>
            </div>

            <div className="absolute bottom-6 text-xs text-slate-600">
                Hint: {ACCESS_CODE}
            </div>
        </div>
    );
  }

  return <MainApp />;
};

export default App;

import React, { useEffect, useRef } from 'react';

interface VisualizerProps {
  analyser: AnalyserNode | null;
  isActive: boolean;
  color?: string;
}

export const Visualizer: React.FC<VisualizerProps> = ({ analyser, isActive, color = '#3b82f6' }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameRef = useRef<number>(0);

  // Use refs for persistent data
  const buffersRef = useRef<{
    dataArray: Uint8Array | null;
    bufferLength: number;
  }>({ dataArray: null, bufferLength: 0 });

  useEffect(() => {
    if (analyser) {
      const bufferLength = analyser.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      buffersRef.current = { dataArray, bufferLength };
    }
  }, [analyser]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    const parent = canvas.parentElement;

    const resizeCanvas = () => {
      if (parent) {
        // Handle high DPI displays for crisp lines
        const dpr = window.devicePixelRatio || 1;
        canvas.width = parent.clientWidth * dpr;
        canvas.height = parent.clientHeight * dpr;
        ctx.scale(dpr, dpr);
        canvas.style.width = `${parent.clientWidth}px`;
        canvas.style.height = `${parent.clientHeight}px`;
      }
    };

    let observer: ResizeObserver | null = null;
    if (parent) {
       observer = new ResizeObserver(() => resizeCanvas());
       observer.observe(parent);
    }
    resizeCanvas();

    const render = () => {
      if (!ctx || !canvas) return;

      const width = parseFloat(canvas.style.width);
      const height = parseFloat(canvas.style.height);

      const centerX = width / 2;
      const centerY = height / 2;
      // Base radius of the inner circle
      const baseRadius = Math.min(width, height) / 6;

      ctx.clearRect(0, 0, width, height);

      // --- IDLE STATE (Disconnected) ---
      if (!isActive) {
         ctx.beginPath();
         ctx.arc(centerX, centerY, baseRadius, 0, 2 * Math.PI);
         ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
         ctx.lineWidth = 1;
         ctx.stroke();

         // Tiny breathing dot in center
         const time = Date.now() / 1000;
         const breathe = (Math.sin(time * 2) + 1) * 0.5;
         ctx.beginPath();
         ctx.arc(centerX, centerY, 2 + breathe * 2, 0, 2 * Math.PI);
         ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
         ctx.fill();

         animationFrameRef.current = requestAnimationFrame(render);
         return;
      }

      // --- ACTIVE STATE ---

      let pulse = 0;
      let dataArray = buffersRef.current.dataArray;

      // Get Audio Data
      if (analyser && dataArray) {
        analyser.getByteFrequencyData(dataArray);

        // Calculate average volume for global pulse
        let sum = 0;
        const binCount = Math.floor(buffersRef.current.bufferLength * 0.7); // Focus on lower-mid freqs
        for (let i = 0; i < binCount; i++) {
          sum += dataArray[i];
        }
        pulse = (sum / binCount) / 255; 
      }

      // Artificial breathing for "Thinking" state (active but silent)
      const time = Date.now() / 1000;
      const breathing = (Math.sin(time * 2) + 1) * 0.15; // Slow breath

      // Effective visual magnitude
      const magnitude = Math.max(pulse, breathing);
      const isSilent = pulse < 0.05;

      // --- DRAWING ---

      // 1. Inner Glow Core
      const gradient = ctx.createRadialGradient(centerX, centerY, baseRadius * 0.5, centerX, centerY, baseRadius * 2);
      gradient.addColorStop(0, `${color}40`); // Hex + opacity
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, baseRadius * 2 + (magnitude * 20), 0, Math.PI * 2);
      ctx.fill();

      // 2. Base Ring
      ctx.beginPath();
      ctx.arc(centerX, centerY, baseRadius + (magnitude * 5), 0, Math.PI * 2);
      ctx.strokeStyle = `${color}80`;
      ctx.lineWidth = 2;
      ctx.stroke();

      // 3. Radial Frequency Bars
      const bars = 64; // Number of bars
      const angleStep = (Math.PI * 2) / bars;

      ctx.lineCap = 'round';

      for (let i = 0; i < bars; i++) {
        let barHeight = 0;

        if (analyser && dataArray && !isSilent) {
             // Map bar index to frequency bin (logarithmic-ish mapping usually looks better, but linear is fine for this)
             // We have fewer bars than bins (usually 128 or 256 bins).
             // Simple mapping:
             const dataIndex = Math.floor((i / bars) * (buffersRef.current.bufferLength * 0.5));
             const value = dataArray[dataIndex] || 0;
             // Scale height
             barHeight = (value / 255) * (baseRadius * 1.5);
             // Minimum visibility
             barHeight = Math.max(barHeight, 4); 
        } else {
             // Idle/Breathing pattern for bars
             // Create a gentle wave effect around the circle
             const wave = Math.sin((i / bars) * Math.PI * 4 + time * 2);
             barHeight = 4 + (wave * 2) + (breathing * 10);
        }

        const angle = i * angleStep - (Math.PI / 2); // Start from top
        const currentRadius = baseRadius + 10 + (magnitude * 5); // Start slightly outside the ring

        const sx = centerX + Math.cos(angle) * currentRadius;
        const sy = centerY + Math.sin(angle) * currentRadius;
        const ex = centerX + Math.cos(angle) * (currentRadius + barHeight);
        const ey = centerY + Math.sin(angle) * (currentRadius + barHeight);

        ctx.beginPath();
        ctx.moveTo(sx, sy);
        ctx.lineTo(ex, ey);
        ctx.strokeStyle = color;
        // Dynamic opacity based on height/loudness
        ctx.globalAlpha = isSilent ? 0.3 : 0.6 + (barHeight / (baseRadius * 1.5)) * 0.4;
        ctx.lineWidth = 3; // Thicker bars
        ctx.stroke();
        ctx.globalAlpha = 1.0;
      }

      animationFrameRef.current = requestAnimationFrame(render);
    };

    render();

    return () => {
      if (observer) observer.disconnect();
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [analyser, isActive, color]);

  return <canvas ref={canvasRef} className="w-full h-full block transform-gpu" />;
};

import React, { useState, useEffect } from 'react';
