    connect,
    disconnect,
    connectionState,
    error,
    groundingMetadata,
    inputAnalyser: inputAnalyserRef.current,
    outputAnalyser: outputAnalyserRef.current,
    isMuted,
    toggleMute,
    videoRef,
    isVideoActive,
    toggleVideo,
    switchCamera,
    isUserSpeaking,
    isAiSpeaking
  };
