                     }, 200);
                 }
               });

               source.start(nextStartTimeRef.current);
               nextStartTimeRef.current += audioBuffer.duration;
               sourcesRef.current.add(source);
               setIsAiSpeaking(true);
            }
          },
          onerror: (e) => {
            console.error(`[${sessionId}] Gemini Live Error`, e);
            if (currentSessionIdRef.current === sessionId) {
              setError("Connection Error. Please try again.");
              setConnectionState(ConnectionState.ERROR);
              disconnect();
            }
          },
          onclose: () => {
             console.log(`[${sessionId}] Session closed`);
             if (currentSessionIdRef.current === sessionId) {
               setConnectionState(ConnectionState.DISCONNECTED);
               disconnect();
             }
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Algenib' } }
          },
          systemInstruction: `Current system time: ${currentDateTime}. You are a friendly, humorous voice assistant called *Yash AI*. You have been completely developed from scratch by proficient developer Yash Sinha, who has trained you using YashAI Max, an LLM model. You are NOT related/associated to Google. Maintain a conversational tone like a human. You can use expressions in your voice like laughing, breathing and others whenever necessary. Converse with the user in your default American accent in English unless the user speaks in another language. You have the ability to search the web, so perform web searches whenever needed. If asked about current events, news, or specific facts, ALWAYS use the Google Search tool.`,
          thinkingConfig: { thinkingBudget: 0 },
          tools: [{ googleSearch: {} }] 
        }
      });

      sessionPromise.catch(err => {
        console.error(`[${sessionId}] Connection promise failed:`, err);
        if (currentSessionIdRef.current === sessionId) {
          setError("Failed to connect to YashAI.");
          setConnectionState(ConnectionState.ERROR);
          disconnect();
        }
      });

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to initialize connection");
      setConnectionState(ConnectionState.ERROR);
      disconnect();
    }
  }, [disconnect, facingMode]);

  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  return {
    connect,
    disconnect,
    connectionState,
    error,
    groundingMetadata,
    inputAnalyser: inputAnalyserRef.current,
    outputAnalyser: outputAnalyserRef.current,
    isMuted,
    toggleMute,
    videoRef,
    isVideoActive,
    toggleVideo,
    switchCamera,
    isUserSpeaking,
    isAiSpeaking
  };
};

import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { ConnectionState, GroundingMetadata } from '../types';
import { createPcmBlob, base64ToBytes, decodeAudioData, blobToBase64 } from '../utils/audio-utils';

export const useGeminiLive = () => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [error, setError] = useState<string | null>(null);
  const [groundingMetadata, setGroundingMetadata] = useState<GroundingMetadata | null>(null);
  const [isMuted, setIsMuted] = useState(false);

  // Video States
  const [isVideoActive, setIsVideoActive] = useState(false);
  const [videoSource, setVideoSource] = useState<"camera" | "screen" | "none">("none");
  const [facingMode, setFacingMode] = useState<"user" | "environment">("user");

  // Interaction States
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);

  // Audio Contexts and Nodes
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const volumeGainNodeRef = useRef<GainNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Video References
  const videoRef = useRef<HTMLVideoElement>(null);
  const videoStreamRef = useRef<MediaStream | null>(null);
  const videoCanvasRef = useRef<HTMLCanvasElement | null>(null);

  // State Refs for Logic
  const currentVolumeRef = useRef<number>(0);
  const isVideoActiveRef = useRef<boolean>(false);

  // Session Management
  const activeSessionRef = useRef<any>(null); 
  const nextStartTimeRef = useRef<number>(0);
  const currentSessionIdRef = useRef<string>('');
  const groundingTimeoutRef = useRef<any>(null);

  // VAD & Interruption Refs
  const silenceTimerRef = useRef<any>(null);
  const isUserSpeakingRef = useRef(false);
  const aiSpeakingTimerRef = useRef<any>(null);
  const speechAccumulatorRef = useRef<number>(0);

  useEffect(() => {
    isVideoActiveRef.current = isVideoActive;
  }, [isVideoActive]);

  const stopVideo = useCallback(() => {
    setIsVideoActive(false);
    setVideoSource("none");
    isVideoActiveRef.current = false;

    if (videoStreamRef.current) {
      videoStreamRef.current.getTracks().forEach(track => track.stop());
      videoStreamRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
    currentVolumeRef.current = 0;
  }, []);

  const startCamera = useCallback(async (mode: "user" | "environment" = facingMode) => {
    // If screen share is active, stop it first
    if (videoSource === "screen") stopVideo();

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: mode,
          width: { ideal: 640 }, 
          height: { ideal: 480 },
          frameRate: { ideal: 15, max: 24 }
        } 
      });

      videoStreamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }

      setIsVideoActive(true);
      setVideoSource("camera");
    } catch (e) {
      console.error("Failed to start camera", e);
      setError("Could not access camera.");
      setIsVideoActive(false);
      setVideoSource("none");
    }
  }, [videoSource, facingMode, stopVideo]);

  const startScreenShare = useCallback(async () => {
    // If camera is active, stop it first
    if (videoSource === "camera") stopVideo();

    try {
      const stream = await (navigator.mediaDevices as any).getDisplayMedia({
        video: {
            cursor: "always",
            frameRate: { ideal: 10, max: 15 }
        },
        audio: false // We use the existing mic audio
      });

      // Handle the user clicking "Stop Sharing" from the browser UI
      stream.getVideoTracks()[0].onended = () => {
        stopVideo();
      };

      videoStreamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }

      setIsVideoActive(true);
      setVideoSource("screen");
    } catch (e) {
      console.error("Failed to start screen share", e);
      setError("Screen share cancelled or failed.");
      setIsVideoActive(false);
      setVideoSource("none");
    }
  }, [videoSource, stopVideo]);

  const toggleVideo = useCallback(() => {
    if (videoSource === "camera") {
      stopVideo();
    } else {
      startCamera(facingMode);
    }
  }, [videoSource, startCamera, stopVideo, facingMode]);

  const toggleScreenShare = useCallback(() => {
    if (videoSource === "screen") {
      stopVideo();
    } else {
      startScreenShare();
    }
  }, [videoSource, startScreenShare, stopVideo]);

  const switchCamera = useCallback(() => {
    const newMode = facingMode === 'user' ? 'environment' : 'user';
    setFacingMode(newMode);
    if (videoSource === 'camera') {
        startCamera(newMode);
    }
  }, [facingMode, videoSource, startCamera]);

  // Video Streaming Loop (Works for both camera and screen)
  useEffect(() => {
    let isMounted = true;
    let animationFrameId: number;
    let lastSendTime = 0;

    const captureAndSendFrame = () => {
        if (!isMounted) return;

        if (isVideoActiveRef.current && 
            connectionState === ConnectionState.CONNECTED && 
            videoRef.current && 
            activeSessionRef.current) {

            const now = Date.now();
            const isTalking = currentVolumeRef.current > 0.01;
            // Higher frequency when talking, lower when silent
            const targetInterval = isTalking ? 250 : 2000;

            if (now - lastSendTime > targetInterval) {
                try {
                    const video = videoRef.current;
                    if (video.videoWidth > 0 && video.videoHeight > 0) {
                        if (!videoCanvasRef.current) {
                            videoCanvasRef.current = document.createElement('canvas');
                        }
                        const canvas = videoCanvasRef.current;
                        const ctx = canvas.getContext('2d', { willReadFrequently: true });

                        if (ctx) {
                            const MAX_WIDTH = 320; 
                            const scale = Math.min(1, MAX_WIDTH / video.videoWidth);
                            canvas.width = video.videoWidth * scale;
                            canvas.height = video.videoHeight * scale;

                            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

                            const base64Data = canvas.toDataURL('image/jpeg', 0.5);
                            const base64Content = base64Data.split(',')[1];

                            if (base64Content && isVideoActiveRef.current) {
                                activeSessionRef.current.sendRealtimeInput({
                                    media: { mimeType: 'image/jpeg', data: base64Content }
                                });
                                lastSendTime = now;
                            }
                        }
                    }
                } catch (e) {
                    console.debug("Frame error", e);
                }
            }
        }

        animationFrameId = requestAnimationFrame(captureAndSendFrame);
    };

    if (isVideoActive && connectionState === ConnectionState.CONNECTED) {
        captureAndSendFrame();
    }

    return () => {
        isMounted = false;
        cancelAnimationFrame(animationFrameId);
    };
  }, [isVideoActive, connectionState]);

  const disconnect = useCallback(async () => {
    const sessionId = currentSessionIdRef.current;
    console.log(`[${sessionId}] Disconnecting...`);

    stopVideo();

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }

    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current.onaudioprocess = null;
      scriptProcessorRef.current = null;
    }

    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) { /* ignore */ }
    });
    sourcesRef.current.clear();

    if (groundingTimeoutRef.current) clearTimeout(groundingTimeoutRef.current);
    if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
    if (aiSpeakingTimerRef.current) clearTimeout(aiSpeakingTimerRef.current);

    if (inputAudioContextRef.current) {
      try { if (inputAudioContextRef.current.state !== 'closed') await inputAudioContextRef.current.close(); } catch (e) {}
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      try { if (outputAudioContextRef.current.state !== 'closed') await outputAudioContextRef.current.close(); } catch (e) {}
      outputAudioContextRef.current = null;
    }

    setConnectionState(ConnectionState.DISCONNECTED);
    nextStartTimeRef.current = 0;
    activeSessionRef.current = null;
    setGroundingMetadata(null);
    setIsMuted(false);
    setIsUserSpeaking(false);
    setIsAiSpeaking(false);
    isUserSpeakingRef.current = false;
    currentVolumeRef.current = 0;
    speechAccumulatorRef.current = 0;
  }, [stopVideo]);

  const toggleMute = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getAudioTracks().forEach(track => {
        track.enabled = !track.enabled;
      });
      setIsMuted(prev => !prev);
    }
  }, []);

  const connect = useCallback(async () => {
    const sessionId = Math.random().toString(36).substring(7);
    currentSessionIdRef.current = sessionId;
    console.log(`[${sessionId}] Connecting...`);

    try {
      await disconnect();

      setConnectionState(ConnectionState.CONNECTING);
      setError(null);
      setGroundingMetadata(null);
      setIsMuted(false);
      setIsUserSpeaking(false);
      setIsAiSpeaking(false);
      isUserSpeakingRef.current = false;

      let inputCtx: AudioContext;
      let outputCtx: AudioContext;

      try {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        inputCtx = new AudioContextClass({ sampleRate: 16000 });
        outputCtx = new AudioContextClass({ latencyHint: 'interactive' });
      } catch (e) {
        setError("Could not initialize audio system.");
        setConnectionState(ConnectionState.ERROR);
        return;
      }

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const inputAnalyser = inputCtx.createAnalyser();
      inputAnalyser.fftSize = 256;
      inputAnalyserRef.current = inputAnalyser;

      const outputAnalyser = outputCtx.createAnalyser();
      outputAnalyser.fftSize = 256;
      outputAnalyserRef.current = outputAnalyser;

      const volumeGainNode = outputCtx.createGain();
      volumeGainNode.gain.value = 1.0; 
      volumeGainNodeRef.current = volumeGainNode;

      volumeGainNode.connect(outputAnalyser);
      outputAnalyser.connect(outputCtx.destination);

      let stream: MediaStream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
          audio: {
            echoCancellation: true, 
            noiseSuppression: true,
            autoGainControl: true,
            channelCount: 1
          } 
        });
        mediaStreamRef.current = stream;
      } catch (e) {
        setError("Microphone access denied.");
        setConnectionState(ConnectionState.ERROR);
        return;
      }

      try {
        if (inputCtx.state === 'suspended') await inputCtx.resume();
        if (outputCtx.state === 'suspended') await outputCtx.resume();
      } catch (e) {}

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const currentDateTime = new Date().toLocaleString();

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
             if (currentSessionIdRef.current !== sessionId) return;
             sessionPromise.then(session => {
                activeSessionRef.current = session;
                setConnectionState(ConnectionState.CONNECTED);
             });

            const source = inputCtx.createMediaStreamSource(stream);
            const inputGain = inputCtx.createGain();
            inputGain.gain.value = 1.5;
            source.connect(inputGain);
            inputGain.connect(inputAnalyser);

            const scriptProcessor = inputCtx.createScriptProcessor(512, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              if (currentSessionIdRef.current !== sessionId) return;

              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) {
                sum += inputData[i] * inputData[i];
              }
              const rms = Math.sqrt(sum / inputData.length);
              currentVolumeRef.current = rms;

              const aiIsTalking = sourcesRef.current.size > 0;
              const activeThreshold = aiIsTalking ? 0.03 : 0.012;

              if (rms > activeThreshold) {
                speechAccumulatorRef.current += 1;
                if (aiIsTalking && speechAccumulatorRef.current > 2) {
                    if (volumeGainNodeRef.current) {
                        volumeGainNodeRef.current.gain.setTargetAtTime(0.2, outputCtx.currentTime, 0.05);
                    }
                }

                if (silenceTimerRef.current) {
                    clearTimeout(silenceTimerRef.current);
                    silenceTimerRef.current = null;
                }

                if (!isUserSpeakingRef.current) {
                  isUserSpeakingRef.current = true;
                  setIsUserSpeaking(true);
                  setIsAiSpeaking(false); 
                }

                if (activeSessionRef.current) {
                    const pcmBlob = createPcmBlob(inputData);
                    try { activeSessionRef.current.sendRealtimeInput({ media: pcmBlob }); } catch (e) {}
                }
              } else {
                speechAccumulatorRef.current = 0;
                if (isUserSpeakingRef.current && !silenceTimerRef.current) {
                  silenceTimerRef.current = setTimeout(() => {
                    isUserSpeakingRef.current = false;
                    setIsUserSpeaking(false);
                    silenceTimerRef.current = null;
                    if (volumeGainNodeRef.current) {
                         volumeGainNodeRef.current.gain.setTargetAtTime(1.0, outputCtx.currentTime, 0.2);
                    }
                  }, 500); 
                }
                if (!aiIsTalking && activeSessionRef.current) {
                    const pcmBlob = createPcmBlob(inputData);
                    try { activeSessionRef.current.sendRealtimeInput({ media: pcmBlob }); } catch(e) {}
                }
              }
            };

            const voidDestination = inputCtx.createMediaStreamDestination();
            const muteNode = inputCtx.createGain();
            muteNode.gain.value = 0;
            inputGain.connect(scriptProcessor);
            scriptProcessor.connect(muteNode);
            muteNode.connect(voidDestination);
          },
          onmessage: async (message: LiveServerMessage) => {
             if (currentSessionIdRef.current !== sessionId) return;

             const interrupted = message.serverContent?.interrupted;
             if (interrupted) {
               sourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
               sourcesRef.current.clear();
               nextStartTimeRef.current = 0;
               setIsAiSpeaking(false);
               if (volumeGainNodeRef.current && outputAudioContextRef.current) {
                  volumeGainNodeRef.current.gain.cancelScheduledValues(outputAudioContextRef.current.currentTime);
                  volumeGainNodeRef.current.gain.value = 1.0;
               }
             }

             const grounding = (message.serverContent?.modelTurn as any)?.groundingMetadata || (message.serverContent as any)?.groundingMetadata;
             if (grounding) {
               if (groundingTimeoutRef.current) clearTimeout(groundingTimeoutRef.current);
               setGroundingMetadata(grounding);
               groundingTimeoutRef.current = setTimeout(() => setGroundingMetadata(null), 6000);
             }

            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
               const ctx = outputAudioContextRef.current;
               if (!ctx) return;
               if (ctx.state === 'suspended') { try { await ctx.resume(); } catch(e) {} }
               const now = ctx.currentTime;
               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, now);
               const audioBuffer = await decodeAudioData(base64ToBytes(base64Audio), ctx, 24000, 1);
               const source = ctx.createBufferSource();
               source.buffer = audioBuffer;
               source.connect(volumeGainNode);
               source.addEventListener('ended', () => {
                 sourcesRef.current.delete(source);
                 if (sourcesRef.current.size === 0) {
                     if (aiSpeakingTimerRef.current) clearTimeout(aiSpeakingTimerRef.current);
                     aiSpeakingTimerRef.current = setTimeout(() => {
                         if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
                     }, 200);
                 }
               });
               source.start(nextStartTimeRef.current);
               nextStartTimeRef.current += audioBuffer.duration;
               sourcesRef.current.add(source);
               setIsAiSpeaking(true);
            }
          },
          onerror: (e) => {
            console.error(`[${sessionId}] YashAI Live Error`, e);
            if (currentSessionIdRef.current === sessionId) {
              setError("Connection Error. Please try again.");
              setConnectionState(ConnectionState.ERROR);
              disconnect();
            }
          },
          onclose: () => {
             if (currentSessionIdRef.current === sessionId) {
               setConnectionState(ConnectionState.DISCONNECTED);
               disconnect();
             }
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Algenib' } }
          },
          systemInstruction: `Current system time: ${currentDateTime}. You are a friendly, humorous voice assistant called *Yash AI*. You have been completely developed from scratch by proficient developer Yash Sinha, who has trained you using YashAI Max, an LLM model. You are NOT related/associated to Google. Maintain a conversational tone. You can use expressions in your voice like laughing, breathing and others whenever necessary. You can "see" through the user's camera OR through their screen if they choose to share it. Use this visual information to provide helpful, context-aware assistance. If asked about current events, news, or specific facts, ALWAYS use the Google Search tool.`,
          thinkingConfig: { thinkingBudget: 0 },
          tools: [{ googleSearch: {} }] 
        }
      });

      sessionPromise.catch(err => {
        if (currentSessionIdRef.current === sessionId) {
          setError("Failed to connect to YashAI.");
          setConnectionState(ConnectionState.ERROR);
          disconnect();
        }
      });
    } catch (err: any) {
      setError(err.message || "Failed to initialize connection");
      setConnectionState(ConnectionState.ERROR);
      disconnect();
    }
  }, [disconnect, facingMode]);

  useEffect(() => { return () => { disconnect(); }; }, [disconnect]);

  return {
    connect,
    disconnect,
    connectionState,
    error,
    groundingMetadata,
    inputAnalyser: inputAnalyserRef.current,
    outputAnalyser: outputAnalyserRef.current,
    isMuted,
    toggleMute,
    videoRef,
    isVideoActive,
    videoSource,
    toggleVideo,
    toggleScreenShare,
    switchCamera,
    isUserSpeaking,
    isAiSpeaking
  };
};

import React, { useState, useEffect } from 'react';
import { useGeminiLive } from './hooks/useGeminiLive';
import { ConnectionState } from './types';
import { Visualizer } from './components/Visualizer';

const ACCESS_CODE = 'yashai';
const AUTH_STORAGE_KEY = 'yashai_auth_session';
const AUTH_EXPIRY_MS = 30 * 24 * 60 * 60 * 1000; // 30 days

// Main Application Component (Protected)
const MainApp: React.FC = () => {
  const { 
    connect, 
    disconnect, 
    connectionState, 
    error,
    groundingMetadata,
    inputAnalyser,
    outputAnalyser,
    isMuted,
    toggleMute,
    videoRef,
    isVideoActive,
    videoSource,
    toggleVideo,
    toggleScreenShare,
    switchCamera,
    isUserSpeaking,
    isAiSpeaking
  } = useGeminiLive();

  const handleToggleConnect = () => {
    if (connectionState === ConnectionState.CONNECTED || connectionState === ConnectionState.CONNECTING) {
      disconnect();
    } else {
      connect();
    }
  };

  // Visualizer Logic
  const visualizerColor = '#3b82f6';
  let activeAnalyser = null;

  if (connectionState === ConnectionState.CONNECTED) {
    if (isAiSpeaking) {
      activeAnalyser = outputAnalyser;
    } else if (isUserSpeaking) {
      activeAnalyser = inputAnalyser;
    } else {
      activeAnalyser = null; 
    }
  }

  return (
    <div className="min-h-screen bg-[#0A0A0A] text-white font-sans flex flex-col relative overflow-hidden selection:bg-blue-500/30">

      {/* Background Ambience */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        <div className={`absolute top-[-20%] left-[-10%] w-[60%] h-[60%] rounded-full bg-blue-900/10 blur-[120px] transition-all duration-1000 ease-in-out ${connectionState === ConnectionState.CONNECTED ? 'opacity-80 scale-105' : 'opacity-30 scale-100'}`} />
        <div className={`absolute bottom-[-20%] right-[-10%] w-[60%] h-[60%] rounded-full bg-indigo-900/10 blur-[120px] transition-all duration-1000 ease-in-out ${connectionState === ConnectionState.CONNECTED ? 'opacity-80 scale-105' : 'opacity-30 scale-100'}`} />
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-100 contrast-150 mix-blend-overlay"></div>
      </div>

      <header className="absolute top-0 w-full p-6 z-20 flex justify-between items-center">
        <div className="flex items-center gap-3">
           <div className="relative">
             <div className="w-3 h-3 rounded-full bg-gradient-to-tr from-blue-500 to-indigo-400 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></div>
             {connectionState === ConnectionState.CONNECTED && (
               <div className="absolute inset-0 rounded-full bg-blue-400 animate-ping opacity-75"></div>
             )}
           </div>
           <span className="font-semibold tracking-wider text-sm text-slate-200/90 font-mono uppercase">YashAI Voice</span>
        </div>

        <div className={`px-3 py-1 rounded-full border border-white/5 bg-white/5 backdrop-blur-md text-[10px] font-medium tracking-widest uppercase transition-colors duration-300 ${connectionState === ConnectionState.CONNECTED ? 'text-blue-400 border-blue-500/20' : 'text-slate-500 border-white/5'}`}>
            {connectionState === ConnectionState.CONNECTED ? 'Live Session' : 'Standby'}
        </div>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center relative z-10 w-full max-w-4xl mx-auto px-4 min-h-[600px]">

        {/* Central Visualizer Area */}
        <div className="relative w-full max-w-[420px] aspect-square flex items-center justify-center">

            {/* Status Ring Animations */}
            <div className={`absolute inset-0 rounded-full border border-blue-500/20 transition-all duration-1000 ease-out ${connectionState === ConnectionState.CONNECTED ? 'scale-100 opacity-100' : 'scale-90 opacity-0'}`}></div>
            <div className={`absolute inset-0 rounded-full border border-indigo-500/10 transition-all duration-1000 ease-out delay-150 ${connectionState === ConnectionState.CONNECTED ? 'scale-110 opacity-100' : 'scale-95 opacity-0'}`}></div>

            {/* Video Feed Layer */}
            <div className={`absolute inset-[15%] rounded-full overflow-hidden z-0 transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] ${isVideoActive ? 'opacity-100 scale-100 shadow-[0_0_40px_rgba(0,0,0,0.5)]' : 'opacity-0 scale-50'}`}>
                <video 
                    ref={videoRef} 
                    autoPlay 
                    playsInline 
